import{_ as o,C as r,o as n,c as s,ai as e,E as i,w as d,a as l}from"./chunks/framework.BH_J6TYN.js";const q=JSON.parse('{"title":"¿Qué es SYNTIfood?","description":"Menú digital híbrido para restaurantes venezolanos con Pedido Rápido a WhatsApp","frontmatter":{"title":"¿Qué es SYNTIfood?","description":"Menú digital híbrido para restaurantes venezolanos con Pedido Rápido a WhatsApp"},"headers":[],"relativePath":"food/que-es-syntifood.md","filePath":"food/que-es-syntifood.md"}'),p={name:"food/que-es-syntifood.md"};function c(u,a,m,h,g,b){const t=r("Note");return n(),s("div",null,[a[1]||(a[1]=e(`<h2 id="¿que-es" tabindex="-1">¿Qué es? <a class="header-anchor" href="#¿que-es" aria-label="Permalink to &quot;¿Qué es?&quot;">​</a></h2><p>SYNTIfood es el producto de SYNTIweb diseñado para <strong>restaurantes, areperas, pastelerías, food trucks y negocios de comida</strong>. Te da un menú digital profesional donde tus clientes ven las categorías con foto, los platos con precio, y te hacen el pedido directo por WhatsApp.</p><p>No es un catálogo genérico — está diseñado específicamente para comida, con estructura de <strong>1 foto por categoría + lista de platos con precio</strong>.</p><h2 id="¿donde-lo-encuentro" tabindex="-1">¿Dónde lo encuentro? <a class="header-anchor" href="#¿donde-lo-encuentro" aria-label="Permalink to &quot;¿Dónde lo encuentro?&quot;">​</a></h2><p>Para crear un SYNTIfood nuevo: <code>syntiweb.com/onboarding</code> → <strong>&quot;Menú Digital&quot;</strong> → Asistente de 5 pasos.</p><p>Tu menú digital queda en <code>tunegocio.syntiweb.com</code>.</p><h2 id="¿que-hace" tabindex="-1">¿Qué hace? <a class="header-anchor" href="#¿que-hace" aria-label="Permalink to &quot;¿Qué hace?&quot;">​</a></h2><ul><li><strong>Menú digital híbrido:</strong> 1 foto representativa por categoría + lista de platos debajo con nombre y precio</li><li><strong>Pedido Rápido → WhatsApp</strong> (plan Anual): Tu cliente toca [+] en cada plato, acumula su pedido y lo envía como mensaje estructurado por WhatsApp</li><li><strong>Tasa BCV automática</strong> (plan Semestral+): Precios se muestran en REF y/o Bs. con tasa del día</li><li><strong>Categorías organizadas:</strong> Entradas, Platos fuertes, Bebidas, Postres, etc.</li><li><strong>Extras y opciones</strong> (plan Semestral+): Tamaño, punto de cocción, extras</li><li><strong>Horarios de atención</strong> con indicador visual de abierto/cerrado</li><li><strong>QR descargable</strong> para las mesas del local</li></ul><h3 id="estructura-del-menu-visual" tabindex="-1">Estructura del menú (visual) <a class="header-anchor" href="#estructura-del-menu-visual" aria-label="Permalink to &quot;Estructura del menú (visual)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│ 🐟 PESCADOS        [1 foto]            │</span></span>
<span class="line"><span>├──────────────────────────┬──────────────┤</span></span>
<span class="line"><span>│ Al ajillo            [+] │  REF 8.00   │</span></span>
<span class="line"><span>│ A la primavera       [+] │  REF 9.00   │</span></span>
<span class="line"><span>│ Frito                [+] │  REF 7.00   │</span></span>
<span class="line"><span>└──────────────────────────┴──────────────┘</span></span>
<span class="line"><span>       [Ver pedido (3 items) →]</span></span></code></pre></div><p>Esta estructura es intencional: <strong>no requiere foto por cada plato</strong>. Solo 1 foto por categoría. El venezolano ya sabe leer un menú tipo restaurante físico.</p><h2 id="¿que-no-hace" tabindex="-1">¿Qué NO hace? <a class="header-anchor" href="#¿que-no-hace" aria-label="Permalink to &quot;¿Qué NO hace?&quot;">​</a></h2><ul><li><strong>No es un carrito de compras</strong> — el Pedido Rápido es un acumulador simple que envía a WhatsApp</li><li><strong>No procesa pagos</strong> — el cliente coordina el pago por WhatsApp</li><li><strong>No tiene delivery integrado</strong> — no calcula envío, no rastrea repartidores</li><li><strong>No tiene inventario</strong> — no descuenta platos agotados automáticamente</li><li><strong>No tiene sistema de reservas</strong> — no agenda mesas</li><li><strong>No permite foto por cada plato</strong> — solo 1 foto por categoría (diseño intencional)</li><li><strong>No tiene carrito persistente</strong> — si el cliente cierra el navegador, se pierde el pedido</li></ul><h2 id="disponibilidad-por-plan" tabindex="-1">Disponibilidad por plan <a class="header-anchor" href="#disponibilidad-por-plan" aria-label="Permalink to &quot;Disponibilidad por plan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Característica</th><th>Básico (REF 9/mes)</th><th>Semestral (REF 39)</th><th>Anual (REF 69/año) ⭐</th></tr></thead><tbody><tr><td>Ítems en menú</td><td>50</td><td>100</td><td>150</td></tr><tr><td>Fotos de categoría</td><td>6</td><td>12</td><td>18</td></tr><tr><td>Categorías</td><td>❌ Sin categorías</td><td>✅</td><td>✅</td></tr><tr><td>Tasa BCV automática</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Extras y opciones</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td>Horarios de atención</td><td>❌</td><td>✅</td><td>✅</td></tr><tr><td><strong>Pedido Rápido → WhatsApp</strong></td><td>❌</td><td>❌</td><td>✅</td></tr></tbody></table>`,15)),i(t,null,{default:d(()=>[...a[0]||(a[0]=[l(" El **Pedido Rápido** es la función estrella de SYNTIfood y solo está disponible en el plan **Anual** (REF 69/año). Sin él, los clientes ven el menú pero deben escribirte manualmente por WhatsApp. ",-1)])]),_:1}),a[2]||(a[2]=e('<h2 id="compite-con" tabindex="-1">Compite con... <a class="header-anchor" href="#compite-con" aria-label="Permalink to &quot;Compite con...&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Alternativa</th><th>Precio</th><th>Lo que le falta vs SYNTIfood</th></tr></thead><tbody><tr><td>Levery</td><td>Más caro</td><td>Sin pedido directo por WhatsApp</td></tr><tr><td>Nedify</td><td>Variable</td><td>Sin estructura de menú venezolano</td></tr><tr><td>Carta impresa</td><td>REF 20 c/vez</td><td>Hay que reimprimir cada vez que cambia un precio</td></tr><tr><td><strong>SYNTIfood Anual</strong></td><td><strong>REF 69/año</strong></td><td>Todo incluido + Pedido Rápido + BCV automático</td></tr></tbody></table><h2 id="ejemplo-practico" tabindex="-1">Ejemplo práctico <a class="header-anchor" href="#ejemplo-practico" aria-label="Permalink to &quot;Ejemplo práctico&quot;">​</a></h2><h3 id="caso-arepera-la-reina-del-maiz-en-maracaibo" tabindex="-1">Caso: Arepera &quot;La Reina del Maíz&quot; en Maracaibo <a class="header-anchor" href="#caso-arepera-la-reina-del-maiz-en-maracaibo" aria-label="Permalink to &quot;Caso: Arepera &quot;La Reina del Maíz&quot; en Maracaibo&quot;">​</a></h3><p>Pedro tiene una arepera con el plan Anual:</p><ol><li>Crea categorías: &quot;Arepas Clásicas&quot; (foto de arepa rellena), &quot;Arepas Premium&quot; (foto de arepa gourmet), &quot;Bebidas&quot; (foto de jugo), &quot;Combos&quot; (foto de combo)</li><li>Agrega ítems: Arepa de queso REF 3, Arepa reina pepiada REF 4, Arepa dominó REF 3.50...</li><li>Activa el Pedido Rápido</li></ol><p>Un cliente escanea el QR en la mesa:</p><ul><li>Ve las categorías con fotos</li><li>Toca [+] en &quot;Arepa reina pepiada&quot; y [+] en &quot;Jugo de guayaba&quot;</li><li>Toca <strong>&quot;Ver pedido (2 items)&quot;</strong></li><li>Toca <strong>&quot;Enviar pedido&quot;</strong></li><li>Se abre WhatsApp con el mensaje estructurado</li></ul><p>Pedro confirma por WhatsApp y prepara el pedido.</p><h2 id="ver-tambien" tabindex="-1">Ver también <a class="header-anchor" href="#ver-tambien" aria-label="Permalink to &quot;Ver también&quot;">​</a></h2><ul><li><a href="/food/categorias-e-items.html">Categorías e ítems</a> — Cómo organizar tu menú</li><li><a href="/food/pedido-rapido.html">Pedido Rápido</a> — El acumulador de platos → WhatsApp</li><li><a href="/food/wizard-food.html">Configurar tu menú</a> — El asistente de primeros pasos</li></ul>',11))])}const A=o(p,[["render",c]]);export{q as __pageData,A as default};
